/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Cadastro Pessoas"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &gridPesRaz.IsEmpty() print printBlockFiltergridPesRaz EndIf If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &PesSts.IsEmpty() &FilterPesStsValueDescription = &PesSts.EnumerationDescription()
print printBlockFilterPesSts EndIf If not &PesIsTra.IsEmpty() &FilterPesIsTraValueDescription = '' Do Case Case &PesIsTra.ToString().Trim() = !"true" &FilterPesIsTraValueDescription = "Transportadoras"
Case &PesIsTra.ToString().Trim() = !"false" &FilterPesIsTraValueDescription = " Todas Pessoas"
EndCase
print printBlockFilterPesIsTra EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESCPF' &PesCpf1.FromString(&GridStateDynamicFilter.Value) If not &PesCpf1.IsEmpty() &PesCpf = &PesCpf1 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector1 = !'RATCOD' &RatCod1.FromString(&GridStateDynamicFilter.Value) If not &RatCod1.IsEmpty() &RatCod = &RatCod1 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDCOD' &PesCidCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod1.IsEmpty() &PesCidCod = &PesCidCod1 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDNOM' &PesCidNom1.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom1.IsEmpty() &PesCidNom = &PesCidNom1 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector1 = !'PESCIDUFECOD' &PesCidUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod1.IsEmpty() &PesCidUfeCod = &PesCidUfeCod1 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector1 = !'PESFAN' &PesFan1.FromString(&GridStateDynamicFilter.Value) If not &PesFan1.IsEmpty() &PesFan = &PesFan1 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector1 = !'PESTRAREGATU' &PesTraRegAtu1.FromString(&GridStateDynamicFilter.Value) If not &PesTraRegAtu1.IsEmpty() &PesTraRegAtu = &PesTraRegAtu1 print printBlockFilterPesTraRegAtu EndIf Case &DynamicFiltersSelector1 = !'PESTRACNV' &PesTraCnv1.FromString(&GridStateDynamicFilter.Value) If not &PesTraCnv1.IsEmpty() &FilterPesTraCnv1ValueDescription = &PesTraCnv1.EnumerationDescription()
&FilterPesTraCnvValueDescription = &FilterPesTraCnv1ValueDescription print printBlockFilterPesTraCnv EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESCPF' &PesCpf2.FromString(&GridStateDynamicFilter.Value) If not &PesCpf2.IsEmpty() &PesCpf = &PesCpf2 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector2 = !'RATCOD' &RatCod2.FromString(&GridStateDynamicFilter.Value) If not &RatCod2.IsEmpty() &RatCod = &RatCod2 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDCOD' &PesCidCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod2.IsEmpty() &PesCidCod = &PesCidCod2 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDNOM' &PesCidNom2.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom2.IsEmpty() &PesCidNom = &PesCidNom2 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector2 = !'PESCIDUFECOD' &PesCidUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod2.IsEmpty() &PesCidUfeCod = &PesCidUfeCod2 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector2 = !'PESFAN' &PesFan2.FromString(&GridStateDynamicFilter.Value) If not &PesFan2.IsEmpty() &PesFan = &PesFan2 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector2 = !'PESTRAREGATU' &PesTraRegAtu2.FromString(&GridStateDynamicFilter.Value) If not &PesTraRegAtu2.IsEmpty() &PesTraRegAtu = &PesTraRegAtu2 print printBlockFilterPesTraRegAtu EndIf Case &DynamicFiltersSelector2 = !'PESTRACNV' &PesTraCnv2.FromString(&GridStateDynamicFilter.Value) If not &PesTraCnv2.IsEmpty() &FilterPesTraCnv2ValueDescription = &PesTraCnv2.EnumerationDescription()
&FilterPesTraCnvValueDescription = &FilterPesTraCnv2ValueDescription print printBlockFilterPesTraCnv EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESCPF' &PesCpf3.FromString(&GridStateDynamicFilter.Value) If not &PesCpf3.IsEmpty() &PesCpf = &PesCpf3 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector3 = !'RATCOD' &RatCod3.FromString(&GridStateDynamicFilter.Value) If not &RatCod3.IsEmpty() &RatCod = &RatCod3 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDCOD' &PesCidCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod3.IsEmpty() &PesCidCod = &PesCidCod3 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDNOM' &PesCidNom3.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom3.IsEmpty() &PesCidNom = &PesCidNom3 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector3 = !'PESCIDUFECOD' &PesCidUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod3.IsEmpty() &PesCidUfeCod = &PesCidUfeCod3 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector3 = !'PESFAN' &PesFan3.FromString(&GridStateDynamicFilter.Value) If not &PesFan3.IsEmpty() &PesFan = &PesFan3 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector3 = !'PESTRAREGATU' &PesTraRegAtu3.FromString(&GridStateDynamicFilter.Value) If not &PesTraRegAtu3.IsEmpty() &PesTraRegAtu = &PesTraRegAtu3 print printBlockFilterPesTraRegAtu EndIf Case &DynamicFiltersSelector3 = !'PESTRACNV' &PesTraCnv3.FromString(&GridStateDynamicFilter.Value) If not &PesTraCnv3.IsEmpty() &FilterPesTraCnv3ValueDescription = &PesTraCnv3.EnumerationDescription()
&FilterPesTraCnvValueDescription = &FilterPesTraCnv3ValueDescription print printBlockFilterPesTraCnv EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order PesCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order PesFan when &OrderedBy = 4 AND &OrderedDsc = False order (PesFan) when &OrderedBy = 4 AND &OrderedDsc = True order PesTraRegAtu when &OrderedBy = 5 AND &OrderedDsc = False order (PesTraRegAtu) when &OrderedBy = 5 AND &OrderedDsc = True order PesStsEfr when &OrderedBy = 6 AND &OrderedDsc = False order (PesStsEfr) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWTransportadora(&gridPesRaz, &PesCod, &PesSts, &PesIsTra, &DynamicFiltersSelector1, &PesCpf1 , &RatCod1, &PesCidCod1, &PesCidNom1, &PesCidUfeCod1, &PesFan1, &PesTraRegAtu1 , &PesTraCnv1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PesCpf2, &RatCod2, &PesCidCod2 , &PesCidNom2, &PesCidUfeCod2, &PesFan2, &PesTraRegAtu2, &PesTraCnv2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &PesCpf3, &RatCod3, &PesCidCod3, &PesCidNom3, &PesCidUfeCod3 , &PesFan3, &PesTraRegAtu3, &PesTraCnv3) &gridPesFan = iif(PesFan.Length() > 30, Substr(PesFan,1, 30) + '...', PesFan) &GridPesTipPessoa = PesIsTra &gridPesCidNom = PesCidUfeCod.Trim() +' / '+ PesCidNom.Trim()
If PesTip = 'J' //JURIDICA &CpfCnpj = PesCnpj Else &CpfCnpj = PesCpf EndIF
&gridPesPrmFon = PesPrmFon &PesStsEfrDescription = PesStsEfr.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWTransportadoraGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWTransportadoraGridState")) Else &GridState.FromXml(&Session.Get(!"WWTransportadoraGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"GRIDPESRAZ" &gridPesRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISTRA" &PesIsTra.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
